code.C:
#include <stdio.h>

struct Person {
    int age;
    char name[101]; // space for null terminator
};

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int i = 0; i < T; ++i) {
        struct Person p;
        struct Person *ptr = &p; // pointer to structure
        scanf("%d", &ptr->age);
        scanf("%100s", ptr->name);
        printf("Age: %d, Name: %s", ptr->age, ptr->name);
        if (i + 1 < T) printf("\n");
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;

struct Person {
    int age;
    string name;
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    for (int i = 0; i < T; ++i) {
        Person p;
        Person *ptr = &p; // pointer to structure
        cin >> ptr->age >> ptr->name;
        cout << "Age: " << ptr->age << ", Name: " << ptr->name;
        if (i + 1 < T) cout << '\n';
    }
    return 0;
}

code.Java:
import java.util.*;

public class Main {
    static class Person {
        int age;
        String name;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        for (int i = 0; i < T; ++i) {
            Person p = new Person();
            p.age = sc.nextInt();
            p.name = sc.next();
            System.out.print("Age: " + p.age + ", Name: " + p.name);
            if (i + 1 < T) System.out.println();
        }
        sc.close();
    }
}

